---- MODULE ATM ----
EXTENDS Integers, Sequences, FiniteSets

VARIABLES state, card, pin, dispensed

(* State constants *)
Idle == 0
CardInserted == 1
PINEntered == 2
Dispensing == 3
Done == 4

(* Initial state *)
Init == /\ state = Idle
        /\ card = {}
        /\ pin = {}
        /\ dispensed = {}

(* Next-state relation *)
Next == 
    \/ /\ state = Idle
       /\ card' = {}
       /\ pin' = {}
       /\ dispensed' = {}
       /\ state' = CardInserted
    \/ /\ state = CardInserted
       /\ card' = Append(card, "CardInserted")
       /\ pin' = {}
       /\ dispensed' = {}
       /\ state' = PINEntered
    \/ /\ state = PINEntered
       /\ card' = Append(card, "PINEntered")
       /\ pin' = {}
       /\ dispensed' = {}
       /\ state' = Dispensing
    \/ /\ state = Dispensing

---- MODULE DistLock ----
EXTENDS Integers, Sequences, FiniteSets

VARIABLES lockHolder, lockRequests

Init == /\ lockHolder = 0
        /\ lockRequests = {}

Next == \/ /\ lockHolder # 0
           /\ lockRequests = {}
           /\ lockHolder' = 0
           /\ lockRequests' = {}
        \/ /\ lockHolder = 0
           /\ lockRequests # {}
           /\ lockHolder' = CHOOSE x \in lockRequests : x
           /\ lockRequests' = lockRequests \ {lockHolder'}
        \/ /\ lockHolder # 0
           /\ lockRequests = {}
           /\ lockHolder' = lockHolder
           /\ lockRequests' = {}

Spec == Init /\ [][Next]_<<lockHolder, lockRequests>>

